   795→    function renderStepIndicator() {
   796→      const stepsCompleted = wizardState ? (wizardState.steps_completed || []) : [];
   797→      const indicator = document.getElementById('stepIndicator');
   798→      indicator.innerHTML = STEPS.map((s, i) => {
   799→        const isCompleted = stepsCompleted.includes(String(s.num)) || stepsCompleted.includes(s.num) || s.num < currentStep;
   800→        const isActive = s.num === currentStep;
   801→        const dotClass = isCompleted && !isActive ? 'completed' : (isActive ? 'active' : '');
   802→        const wrapperClass = isCompleted && !isActive ? 'completed' : (isActive ? 'active' : '');
   803→        const connector = i < STEPS.length - 1
   804→          ? `<div class="step-connector ${isCompleted ? 'completed' : ''}"></div>`
   805→          : '';
   806→        return `
   807→          <div class="step-dot-wrapper ${wrapperClass}">
   808→            <div class="step-dot ${dotClass}">
   809→              ${isCompleted && !isActive ? '✓' : s.num}
   810→            </div>
   811→            <span class="step-label">${s.label}</span>
   812→          </div>
   813→          ${connector}
   814→        `;
   815→      }).join('');
   816→    }
