   725→// Get wizard progress for current candidate
   726→router.get('/wizard/progress', authMiddleware, async (req, res) => {
   727→  try {
   728→    // Get candidate's active checklist
   729→    const checklist = await pool.query(
   730→      `SELECT oc.*, o.title as offer_title, o.company_name, o.salary, o.start_date,
   731→              j.title as job_title
   732→       FROM onboarding_checklists oc
   733→       JOIN offers o ON oc.offer_id = o.id
   734→       LEFT JOIN jobs j ON o.job_id = j.id
   735→       WHERE oc.candidate_id = $1
   736→       ORDER BY oc.created_at DESC LIMIT 1`,
   737→      [req.user.id]
   738→    );
   739→
   740→    if (checklist.rows.length === 0) {
   741→      return res.json({ has_onboarding: false });
   742→    }
   743→
   744→    const cl = checklist.rows[0];
   745→
   746→    // Get or create wizard data
   747→    let wizardData = await pool.query(
   748→      'SELECT * FROM candidate_onboarding_data WHERE candidate_id = $1 AND checklist_id = $2',
   749→      [req.user.id, cl.id]
   750→    );
   751→
   752→    if (wizardData.rows.length === 0) {
   753→      // First time visiting the real wizard — create fresh wizard data
   754→      wizardData = await pool.query(
   755→        `INSERT INTO candidate_onboarding_data (candidate_id, checklist_id)
   756→         VALUES ($1, $2)
   757→         RETURNING *`,
   758→        [req.user.id, cl.id]
   759→      );
   760→
   761→      // If the old fake auto-complete system marked the checklist as "completed"
   762→      // but no real wizard data exists, reset the checklist so the candidate
   763→      // can go through the real flow
   764→      if (cl.status === 'completed' || cl.status === 'in_progress') {
   765→        const existingDocs = await pool.query(
   766→          'SELECT COUNT(*) as cnt FROM onboarding_documents WHERE candidate_id = $1 AND checklist_id = $2',
   767→          [req.user.id, cl.id]
   768→        );
   769→        if (parseInt(existingDocs.rows[0].cnt) === 0) {
   770→          // No real documents = the old system faked it. Reset.
   771→          await pool.query(
   772→            `UPDATE onboarding_checklists SET
   773→              status = 'in_progress',
   774→              completed_items = '[]'::jsonb,
   775→              completed_at = NULL,
   776→              updated_at = NOW()
   777→             WHERE id = $1`,
   778→            [cl.id]
   779→          );
   780→          cl.status = 'in_progress';
   781→          cl.completed_items = [];
   782→        }
   783→      }
   784→    }
   785→
   786→    // Get existing documents
   787→    const documents = await pool.query(
   788→      'SELECT * FROM onboarding_documents WHERE candidate_id = $1 AND checklist_id = $2 ORDER BY created_at',
   789→      [req.user.id, cl.id]
   790→    );
   791→
   792→    res.json({
   793→      has_onboarding: true,
   794→      checklist: cl,
   795→      wizard: wizardData.rows[0],
   796→      documents: documents.rows
   797→    });
   798→  } catch (err) {
   799→    console.error('Error getting wizard progress:', err);
   800→    res.status(500).json({ error: 'Failed to get wizard progress' });
   801→  }
   802→});
