  1180→router.get('/recruiter/document/:document_id/download', authMiddleware, async (req, res) => {
  1181→  try {
  1182→    if (!req.user.company_id) {
  1183→      return res.status(403).json({ error: 'Only recruiters can download documents' });
  1184→    }
  1185→
  1186→    const doc = await pool.query(
  1187→      `SELECT od.*, u.name as candidate_name, u.email as candidate_email
  1188→       FROM onboarding_documents od
  1189→       JOIN users u ON od.candidate_id = u.id
  1190→       WHERE od.id = $1`,
  1191→      [req.params.document_id]
  1192→    );
  1193→
  1194→    if (doc.rows.length === 0) {
  1195→      return res.status(404).json({ error: 'Document not found' });
  1196→    }
  1197→
  1198→    const d = doc.rows[0];
  1199→
  1200→    // Verify access: document must belong to a candidate from this recruiter's company
  1201→    const offerCheck = await pool.query(
  1202→      `SELECT id FROM offers WHERE candidate_id = $1 AND company_id = $2 LIMIT 1`,
  1203→      [d.candidate_id, req.user.company_id]
  1204→    );
  1205→    if (offerCheck.rows.length === 0) {
  1206→      return res.status(403).json({ error: 'Access denied' });
  1207→    }
  1208→
  1209→    const content = typeof d.document_content === 'string'
  1210→      ? JSON.parse(d.document_content)
  1211→      : (d.document_content || {});
  1212→
  1213→    // Generate printable HTML document
  1214→    const html = generatePrintableDocument(d, content);
  1215→
  1216→    res.setHeader('Content-Type', 'text/html');
  1217→    res.setHeader('Content-Disposition', `inline; filename="${d.document_type.replace(/[^a-zA-Z0-9]/g, '_')}_${d.candidate_name.replace(/[^a-zA-Z0-9]/g, '_')}.html"`);
  1218→    res.send(html);
  1219→  } catch (err) {
