// HireLoop Main JavaScript

// Auth state
let currentUser = null;
let _checkAuthPromise = null; // Prevent race conditions with double checkAuth() calls
const TOKEN_KEY = 'rekrutai_token';
const REFRESH_KEY = 'rekrutai_refresh';

input.old_string:
try {
  const userRes = await fetch('/api/auth/me', { headers: { 'Authorization': `Bearer ${token}` } });
  if (userRes.ok) {
    const userData = await userRes.json();
    document.getElementById('user-name').textContent = userData.name || 'User';
    document.getElementById('user-avatar').textContent = (userData.name || 'U')[0].toUpperCase();
    if (document.getElementById('dropdown-user-name')) {
      document.getElementById('dropdown-user-name').textContent = userData.name || 'User';
      document.getElementById('dropdown-user-email').textContent = userData.email || '';
    }
  }
} catch(e) { /* ignore */ }

