    if (document.getElementById('dropdown-user-name')) {
      document.getElementById('dropdown-user-name').textContent = user.name || 'User';
      document.getElementById('dropdown-user-email').textContent = user.email || '';
    }
  }
} catch(e) { /* ignore */ }

